import io.harbor.textd.core.TextDaemon;
import java.lang.ref.WeakReference;
import java.lang.reflect.Field;
import java.nio.file.Path;
import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.atomic.AtomicReference;

public class LeakProbe {
  public static void main(String[] args) throws Exception {
    Path jar = Path.of("build/plugins/customer-default.jar");
    List<WeakReference<ClassLoader>> refs = new ArrayList<>();
    TextDaemon daemon = new TextDaemon(jar, 4);
    try {
      Field revisionsField = TextDaemon.class.getDeclaredField("revisions");
      revisionsField.setAccessible(true);
      Object revisions = revisionsField.get(daemon);
      Field currentField = revisions.getClass().getDeclaredField("current");
      currentField.setAccessible(true);
      for (int i = 1; i <= 4; i++) {
        daemon.reload(i);
        daemon.processBatch(List.of("alpha beta gamma", "alpha beta gamma", "alpha beta gamma", "alpha beta gamma"));
        Object atomic = currentField.get(revisions);
        Object frame = ((AtomicReference<?>) atomic).get();
        Field loadedField = frame.getClass().getDeclaredField("loadedGeneration");
        loadedField.setAccessible(true);
        Object loaded = loadedField.get(frame);
        Field clField = loaded.getClass().getDeclaredField("classLoader");
        clField.setAccessible(true);
        ClassLoader loader = (ClassLoader) clField.get(loaded);
        refs.add(new WeakReference<>(loader));
      }
    } finally {
      daemon.close();
      daemon = null;
    }
    for (int i = 0; i < 5; i++) {
      System.gc();
      Thread.sleep(100);
    }
    int alive = 0;
    for (int i = 0; i < refs.size(); i++) {
      if (refs.get(i).get() != null) {
        alive++;
        System.out.println("loader-" + (i + 1) + " alive");
      }
    }
    System.out.println("alive=" + alive);
  }
}
